            if match:
                hour = int(match.group(1))
                minute = int(match.group(2))
                period = match.group(3)
            else:
                return None, None
        else:
            # Format: "9PM" or "9 PM"
            time_part = time_str.replace(' ', '')
            match = re.match(r'(\d{1,2})(AM|PM)', time_part)
